SELECT metric_id, value
FROM bank_industry_data
WHERE year = 2023 AND metric_id = 1;

SELECT bank_name, employee_count 
FROM banks 
ORDER BY employee_count DESC;

SELECT investment_type, SUM(investment_value) AS total_investment_value
FROM investor_portfolio
GROUP BY investment_type;

SELECT SUM(investment_value) AS total_investment_value
FROM investor_portfolio
WHERE investor_id = 1;

SELECT MAX(investment_value) AS max_investment_value, investment_name
FROM investor_portfolio
WHERE investor_id = 0;

SELECT investment_name 
FROM investor_portfolio 
WHERE portfolio_id = 1;
